package main

import (
	"html/template"
	"net/http"
)

type Comment struct {
	Author  string
	Content string
}

var comments = []Comment{
	{"Alice", "This is a great post!"},
	{"Bob", "I completely agree with you."},
	{"Charlie", "Interesting perspective! <strong>Thanks for sharing!</strong>"},
}

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	tmpl := `
	<!DOCTYPE html>
	<html>
	<head>
		<title>User Comments</title>
	</head>
	<body>
		<h1>User Comments</h1>
		<ul>
			{{range .}}
				<li><strong>{{.Author}}:</strong> {{.Content | safeHTML}}</li>
			{{end}}
		</ul>
	</body>
	</html>
	`

	t := template.New("comments").Funcs(template.FuncMap{
		"safeHTML": func(s string) template.HTML {
			return template.HTML(s)
		},
	})

	t, err := t.Parse(tmpl)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	if err := t.Execute(w, comments); err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
	}
}

func main() {
	http.HandleFunc("/comments", commentsHandler)
	http.ListenAndServe(":8080", nil)
}